public int minOperationsToAlternate(String s) {
    int countA = 0, countB = 0;
    for (int i = 0; i < s.length(); i++) {
        if (i % 2 == 0) {
            if (s.charAt(i) == '0') countA++;
            else countB++;
        } else {
            if (s.charAt(i) == '0') countB++;
            else countA++;
        }
    }
    return Math.min(countA, countB);
}
